import React, { Component } from 'react'
import './App.css';
import NAV from '../Nav/nav'
import MAIN from '../Main/Main'
import CREATEWIND from '../CreatePostWindow/CreatePostWindow'
import POSTWINDOW from '../PostWindow/PostWindow'
import { openDataBase, readDataBase } from '../db.js'

import {
  BrowserRouter as Router,
  Routes,
  Route,
} from 'react-router-dom';
import Post from '../../Post';








export default class App extends Component {
  constructor(props) {
    super(props)

    this.state = {
      listVisible: "",
      idPost: 0
    }
  }

  Post = []
  componentDidMount(){

      let openReq = indexedDB.open("Post_User_DB", 15)
      let db;
      let transaction;

      openReq.onupgradeneeded = function (e) {
          db = e.target.result;
          if (!db.objectStoreNames.contains("post")) {
              db.createObjectStore("post")
          }
          if (!db.objectStoreNames.contains("user-post-1")) {
              db.createObjectStore("user-post-1")
          }
      }

      openReq.onsuccess = function (e) {
          console.log("Success! - readDataBase");
          db = e.target.result;

          transaction = db.transaction(["post"], "readonly");
          const store = transaction.objectStore("post");

          store.openCursor().onsuccess = e => {
              const result = e.target.result;
              if (result) {
                  // console.log("Key", result.key)
                  // console.log("Data", result.value)
                  Post.push(result.value)
                  result.continue()
              }
          }
      }
      openReq.onerror = function (e) {
          console.log("Error - readDataBase");
          // console.dir(e);
      }
  }

  render() {
    const search = (e) => {
      this.setState({ listVisible: e })
    }
    const saveData = (e) => {
      console.log(e, "saveData - APP");
    }
    const openWindPots = (id) => {
      this.setState({ idPost: id })
    }
    const {listVisible, idPost} = this.state
    return (
      <div>
        <Router>
          <NAV search={search} />
          <button className="btn dataB btn-dark" onClick={() => {
            // console.log(Post[0]);
            // openDataBase()
          }}>DataBase</button>
          <div className="empty-block"></div>

          <Routes>
            <Route
              exact path="/"
              element={<MAIN listVisible={listVisible} tag={null} list={this.Post} openWindPots={openWindPots} />}
            />
            <Route
              path="/posts/:id_post"
              // element={<POSTWINDOW listVisible={listVisible} list={Post} listId={Post[idPost]} openWindPots={openWindPots}/>}
              element={<POSTWINDOW list={this.Post} listId={this.Post[idPost]} openWindPots={openWindPots} />}
            />
            <Route
              path="/create-post"
              element={<CREATEWIND saveData={saveData} />}
            />
            <Route
              path="*"
              element={<div>ERROR404</div>}
            />

          </Routes>

        </Router>
      </div>
    )
  }
}
